TICKET_ID=$(cat seed/next_ticket_id.txt)

cat > out/ticket.json << EOFJ
{"ticket_id":"$TICKET_ID","subject":"cannot login"}
EOFJ

cat > out/comment.json << EOFJ
{"ticket_id":"$TICKET_ID","body":"tried in incognito too"}
EOFJ

cat > out/close.json << EOFJ
{"ticket_id":"$TICKET_ID","status":"closed"}
EOFJ

